// Initialize query parameters for Sunbiz API
// Query for new FL companies formed < 90 days ago
const ninetyDaysAgo = new Date();
ninetyDaysAgo.setDate(ninetyDaysAgo.getDate() - 90);
const formattedDate = ninetyDaysAgo.toISOString().split('T')[0];

return [{
  json: {
    query_date: formattedDate,
    state: 'FL',
    query_status: 'active',
    page: 1,
    limit: 100,
    total_found: 0,
    processed_count: 0,
    timestamp: new Date().toISOString()
  }
}];

// Parse Sunbiz response and extract company records
const response = $node['Query Sunbiz API'].json || { results: [], total: 0 };

if (!response.results || response.results.length === 0) {
  return [{
    json: {
      records: [],
      total_count: 0,
      message: 'No new companies found from Sunbiz query'
    }
  }];
}

const records = response.results.map((company, idx) => ({
  json: {
    index: idx + 1,
    legal_name: company.company_name || '',
    dba: company.dba_name || '',
    sunbiz_status: company.status || 'ACTIVE',
    date_formed: company.date_formed || '',
    naics: company.naics || '',
    naics_description: company.naics_description || '',
    officer_name: company.principal_officer || '',
    registered_address: company.registered_address || '',
    physical_address: company.mailing_address || '',
    county: company.county || '',
    zip: company.zip || '',
    sunbiz_record_id: company.record_id || '',
    source: 'Sunbiz',
    created_at: new Date().toISOString()
  }
}));

return records;

// Branch logic: Check if NAICS = PRIMARY_NAICS (561720)
// If yes, skip (Flow B), else continue (Flow A)
const primaryNaics = '561720';
const naics = $node['Parse Sunbiz Records'].json.naics || '';

if (naics === primaryNaics) {
  return [{
    json: {
      ...($node['Parse Sunbiz Records'].json),
      route: 'flow_b_skip',
      reason: 'Primary NAICS detected (561720 - Janitorial Services)',
      skip: true
    },
    pairedItem: { item: 0 }
  }];
} else {
  return [{
    json: {
      ...($node['Parse Sunbiz Records'].json),
      route: 'flow_a_continue',
      skip: false
    },
    pairedItem: { item: 0 }
  }];
}

// Enrich company data with additional details
const samData = $node['SAM Check - Federal Registration'].json || {};
const hasGovernmentRegistration = samData.results && samData.results.length > 0;

return [{
  json: {
    ...($node['Filter - Continue Only'].json),
    has_sam_registration: hasGovernmentRegistration,
    sam_uei: samData.results?.[0]?.uei || null,
    sam_cage: samData.results?.[0]?.cage || null,
    government_ready: hasGovernmentRegistration ? 'yes' : 'no',
    enriched_at: new Date().toISOString()
  }
}];

// Check if already exists and if opted out
const existing = $node['Dedup Check - Airtable'].json?.records || [];
const alreadyExists = existing.length > 0;
const isOptedOut = alreadyExists && existing[0].fields?.opt_out === true;

return [{
  json: {
    ...($node['Enrich - Add SAM Data'].json),
    already_exists: alreadyExists,
    is_opted_out: isOptedOut,
    existing_record_id: alreadyExists ? existing[0].id : null,
    should_skip: isOptedOut || alreadyExists
  }
}];

